#include<bits/stdc++.h>
using namespace std;
int main(){
    string x;
    cin>>x;
    int xx,yy;
    int n=x.size();
    for(int i=0;i<n;i++){
        if(x[i]=='O'){
            xx=i;
            break;
        }
        }
    for(int i=n-1;i>=0;i--){
        if(x[i]=='O'){
            yy=i;
            break;
        }
        }
    if(xx==n-1&&yy==0){
        cout<<1;
        return 0;
    }
    if(xx==0&&yy==n-1){
        cout<<2;
        return 0;
    }
    int ans=0;
    for(int i=xx;i<=yy;i++) if(x[i]=='I') ans++;
    int xxx=0,yyy=0,maxx=0,maxnx=0,maxny=0,ans2=0;
    for(int i=0;i<n;i++){
        if(x[i]=='O'){
            if(xxx==-1) xxx=i;
            yyy=i;
            if(yyy-xxx>maxx){
                maxx=yyy-xxx;
                maxnx=xxx;
                maxny=yyy;
            }

        }else{
            xxx=-1;
        }
    }
    for(int i=0;i<maxnx;i++){
        if(x[i]=='O'){
            ans2++;
        }
    }
    for(int i=n-1;i>maxny;i--){
        if(x[i]=='O'){
            ans2++;
        }
    }
    cout<<min(ans,ans2);
}
